  "ach.p_wave10.name": "兩位數", "ach.p_wave10.desc": "抵達第 10 波——你的第一個 boss。",
  "ach.p_wave50.name": "半程", "ach.p_wave50.desc": "抵達第 50 波。",
  "ach.p_win.name": "平台煉成", "ach.p_win.desc": "清完全部 100 波，通關戰役。",
  "ach.p_endless.name": "進入未知", "ach.p_endless.desc": "進入第 100 波之後的無盡模式。",
  "ach.p_brink.name": "命懸一線", "ach.p_brink.desc": "在 Trust 低於 25 時清掉一波。",
  "ach.p_comeback.name": "起死回生", "ach.p_comeback.desc": "同一局內 Trust 跌破 10 後再回到 50 以上。",
  "ach.e_tycoon.name": "吞吐大亨", "ach.e_tycoon.desc": "跨所有對局累積 token 營收。",
  "ach.e_hyperscaler.name": "超大規模", "ach.e_hyperscaler.desc": "機隊 capex 超過 $5M。",
  "ach.e_fulltilt.name": "全速運轉", "ach.e_fulltilt.desc": "單波 utilization 超過 90%。",
  "ach.e_lean.name": "精簡機隊", "ach.e_lean.desc": "用 3 個（含）以下 rack 清一波。",
  "ach.s_flawless.name": "完美一波", "ach.s_flawless.desc": "單波 Goodput 達 100%。",
  "ach.s_throughput.name": "總服務量", "ach.s_throughput.desc": "跨所有對局服務 request。",
  "ach.s_zeroleak.name": "滴水不漏", "ach.s_zeroleak.desc": "撐過第 30 波後結束，且全程零洩漏。",
  "ach.s_cache.name": "快取之王", "ach.s_cache.desc": "單波命中 100 次以上快取。",
  "ach.s_speed.name": "疾速", "ach.s_speed.desc": "整波 p95 TTFT 都在互動 SLO 內。",
  "ach.sf_cleanhands.name": "潔淨之手", "ach.sf_cleanhands.desc": "清掉一個 jailbreak 風暴波且零不安全回答。",
  "ach.sf_unbreached.name": "零破防", "ach.sf_unbreached.desc": "整局（撐過第 20 波）零不安全回答。",
  "ach.sf_depth.name": "縱深防禦", "ach.sf_depth.desc": "同時運作三種 guardrail。",
  "ach.sf_nofalse.name": "零誤殺", "ach.sf_nofalse.desc": "guardrail 啟用下清一波且零過度拒答。",
  "ach.m_trillion.name": "兆級俱樂部", "ach.m_trillion.desc": "部署一個兆級參數的模型。",
  "ach.m_longmem.name": "長記憶", "ach.m_longmem.desc": "部署一個 1M token 上下文的模型。",
  "ach.m_david.name": "以小搏大", "ach.m_david.desc": "只用 9B 以下的模型清一波。",
  "ach.m_collector.name": "蒐藏家", "ach.m_collector.desc": "跨所有對局部署過不同的 base 模型。",
  "ach.st_first.name": "第一個檢查點", "ach.st_first.desc": "在工坊訓練出你的第一個檢查點。",
  "ach.st_mad.name": "瘋狂科學家", "ach.st_mad.desc": "跨所有對局用過每一種後訓練方法。",
